import { onMounted, ref } from 'vue';
import { NForm, NFormItem, NInput, NButton, NSpace } from 'naive-ui';
import { GetOne, Add, Update } from './task_base_Request';
import { translate } from '@utility/i18n.js';
const inPara = defineProps({
  initId: String,
});

const emit = defineEmits(['sheetSubmit']);

const formRef = ref(null); //表格
const sheetData = ref({}); //表单数据
const isNew = ref(true);   //是否是新建

//表单规则
const sheetRules = {
    silo_type: [
        {
            required: true,
            message: translate.t('库型') + translate.t('不能为空'),
            trigger: ['input', 'blur'],
        },
    ],
};

onMounted(() => {
    if (inPara.initId != '') {
        isNew.value = false;
        GetOne(inPara.initId).then((res) => {
            sheetData.value = res;
        });
    }
});

//提交
function btnSubmit() {
    formRef.value
        ?.validate((errors) => {
            if (!errors) {
                if (isNew.value) {
                    Add(sheetData.value).then((res) => {
                        emit('sheetSubmit', 'done');
                    });
                } else {
                    Update(sheetData.value).then((res) => {
                        emit('sheetSubmit', 'done');
                    });
                }
            }
        })
        .catch((err) => {
            window.$message.warning(err[0][0].message);
        });
}

//取消
function btnCancel() {
  emit('sheetSubmit', 'cancel');
}

</script>

